from typing import List

def min_operations(nums: List[int]) -> int:
    nums = sorted(nums)
    operations = 0
    for i in range(1, len(nums)):
        if nums[i] <= nums[i - 1]:
            operations += nums[i - 1] - nums[i] + 1
            nums[i] = nums[i - 1] + 1
    return operations
